import React from 'react';

const PropertyCard = ({ property }) => {
  return (
    <div className="w-[280px] bg-white rounded-3xl shadow-md border border-slate-100 overflow-hidden group">
      {/* Imagen con Tag */}
      <div className="h-48 w-full relative overflow-hidden">
        <img 
          src={property.mainImage} 
          alt={property.title} 
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
        />
        <div className="absolute top-3 right-3 bg-blue-600 text-white text-[10px] font-bold px-3 py-1 rounded-full uppercase">
          {property.tags[0]}
        </div>
      </div>

      {/* Info de la propiedad */}
      <div className="p-5">
        <h3 className="text-[#0F172A] font-bold text-lg leading-tight mb-2 h-12 overflow-hidden">
          {property.title}
        </h3>
        <p className="text-[#2563eb] font-extrabold text-xl mb-4">
          {property.price}
        </p>
        
        {/* Detalles Aesthetic */}
        <div className="flex items-center gap-4 text-slate-500 text-sm mb-5 border-t border-slate-50 pt-4">
          <div className="flex items-center gap-1.5">
            <span className="text-blue-500 text-lg">◨</span>
            <span>{property.beds} Hab</span>
          </div>
          <div className="flex items-center gap-1.5">
            <span className="text-blue-500 text-lg">▣</span>
            <span>{property.area}</span>
          </div>
        </div>

        {/* Botón Ver Detalles */}
        <button 
          onClick={() => alert('Próximo paso: Abriremos la galería de fotos aquí')}
          className="w-full bg-[#f1f5f9] hover:bg-[#0F172A] text-[#1e293b] hover:text-white font-bold py-3 rounded-xl transition-all uppercase text-[11px] tracking-widest border border-slate-200 hover:border-[#0F172A]"
        >
          Ver Detalles
        </button>
      </div>
    </div>
  );
};

export default PropertyCard;
